alter table public.profiles add column if not exists status text not null default 'active' check(status in ('active','invited','suspended'));
alter table public.profiles add column if not exists updated_at timestamptz not null default now();
create table if not exists public.notifications(id uuid primary key default gen_random_uuid(),user_id uuid references public.profiles(id) on delete cascade,title text not null,body text,kind text not null default 'info',read_at timestamptz,created_at timestamptz not null default now());
create table if not exists public.audit_logs(id bigint generated always as identity primary key,actor_id uuid references public.profiles(id),action text not null,entity_type text not null,entity_id text,metadata jsonb not null default '{}'::jsonb,created_at timestamptz not null default now());
create table if not exists public.app_settings(id uuid primary key default gen_random_uuid(),key text unique not null,value jsonb not null default '{}'::jsonb,updated_by uuid references public.profiles(id),updated_at timestamptz not null default now());
alter table public.notifications enable row level security;alter table public.audit_logs enable row level security;alter table public.app_settings enable row level security;
create or replace function public.current_role() returns text language sql stable security definer set search_path=public as $$select role from public.profiles where id=auth.uid()$$;
drop policy if exists "admins manage profiles" on public.profiles;create policy "admins manage profiles" on public.profiles for all to authenticated using(public.current_role()='super_admin') with check(public.current_role()='super_admin');
drop policy if exists "operations manage vehicles" on public.vehicles;create policy "operations manage vehicles" on public.vehicles for all to authenticated using(public.current_role() in ('super_admin','fleet_manager','dispatcher')) with check(public.current_role() in ('super_admin','fleet_manager','dispatcher'));
drop policy if exists "operations manage orders" on public.orders;create policy "operations manage orders" on public.orders for all to authenticated using(public.current_role() in ('super_admin','fleet_manager','dispatcher')) with check(public.current_role() in ('super_admin','fleet_manager','dispatcher'));
drop policy if exists "finance manage funds" on public.operational_funds;create policy "finance manage funds" on public.operational_funds for all to authenticated using(public.current_role() in ('super_admin','finance_approver')) with check(public.current_role() in ('super_admin','finance_approver'));
drop policy if exists "operations manage issues" on public.field_issues;create policy "operations manage issues" on public.field_issues for all to authenticated using(public.current_role() in ('super_admin','fleet_manager','dispatcher')) with check(public.current_role() in ('super_admin','fleet_manager','dispatcher'));
create policy "own notifications" on public.notifications for all to authenticated using(user_id=auth.uid() or public.current_role()='super_admin') with check(user_id=auth.uid() or public.current_role()='super_admin');
create policy "admins read audit" on public.audit_logs for select to authenticated using(public.current_role()='super_admin');create policy "users write own audit" on public.audit_logs for insert to authenticated with check(actor_id=auth.uid());
create policy "authenticated read settings" on public.app_settings for select to authenticated using(true);create policy "admins manage settings" on public.app_settings for all to authenticated using(public.current_role()='super_admin') with check(public.current_role()='super_admin');
insert into public.app_settings(key,value) values('operations','{"timezone":"Asia/Jakarta","gps_stale_minutes":10,"sla_warning_minutes":30}'::jsonb) on conflict(key) do nothing;
do $$ begin alter publication supabase_realtime add table public.notifications;exception when duplicate_object then null;end $$;
